void MuzykaStop( int nrRuchu )

{

   if( (nrRuchu >= 0) && (nrRuchu<=23) )

   {

      if( biezacyKlawisz > -1 )

      {

            //Sound_Holder.Stop( nrRuchu );

            Sprite_Holder.SetDeep( nrRuchu, 0 );

            Sprite_Holder.ChangePhase( nrRuchu, 0 );

            biezacyKlawisz = -1;

      }

   }



   if( (nrRuchu >= 24) && (nrRuchu<=28) )

   {

         // wylaczenie poprzedniego bebna

      int nrBebna = nrRuchu-24;



      if( aktywnyPodklad[nrBebna] )

      {

            Sound_Holder.Stop( nrRuchu );

            Sprite_Holder.ChangePhase( nrRuchu, 0 );

            aktywnyPodklad[nrBebna]=0;

      }

   }

}





