void Sprite_Holder.MouseClickOnDown(int spriteID)

{

   if( akcja == 3 ) 

      return;



   if( (spriteID >= 24) && (spriteID<=28) && (akcja!=0))

      return;



   if( (spriteID >= 0) && (spriteID<=23) )

   {

      if( biezacyKlawisz == -1 )

         Muzyka( spriteID, 1 );

      return;

   }



   if( (spriteID >= 24) && (spriteID<=28) )

   {

      Sound_Holder.PlayDSound(29);

      Muzyka( spriteID, 1 );

      return;

   }







   switch( spriteID )

   {

      case 29:   // sciszanie 

         if( glosnoscKlawiatury > -2000 )

         {

            Sound_Holder.PlayDSound(31);

            glosnoscKlawiatury -= 100;



            Sound_Holder.SetPlayDSoundParameters( 24, glosnoscKlawiatury, 0, 0 );

            Sound_Holder.SetPlayDSoundParameters( 25, glosnoscKlawiatury, 0, 0 );

            Sound_Holder.SetPlayDSoundParameters( 26, glosnoscKlawiatury, 0, 0 );

            Sound_Holder.SetPlayDSoundParameters( 27, glosnoscKlawiatury, 0, 0 );

            Sound_Holder.SetPlayDSoundParameters( 28, glosnoscKlawiatury, 0, 0 );



            Sprite_Holder.ChangePhase( spriteID, 1 );

         }

         break;



      case 30:   // zglasnianie 

         if( glosnoscKlawiatury < 0 )

         {

            Sound_Holder.PlayDSound(31);

            glosnoscKlawiatury += 100;



            Sound_Holder.SetPlayDSoundParameters( 24, glosnoscKlawiatury, 0, 0 );

            Sound_Holder.SetPlayDSoundParameters( 25, glosnoscKlawiatury, 0, 0 );

            Sound_Holder.SetPlayDSoundParameters( 26, glosnoscKlawiatury, 0, 0 );

            Sound_Holder.SetPlayDSoundParameters( 27, glosnoscKlawiatury, 0, 0 );

            Sound_Holder.SetPlayDSoundParameters( 28, glosnoscKlawiatury, 0, 0 );



            Sprite_Holder.ChangePhase( spriteID, 1 );

         }

         break;



      case 32:   // przejscie do nastepnej planszy

         Sound_Holder.PlayDSound(29);

         Sprite_Holder.ChangePhase( spriteID, 1 );

         LoadPage("cuda_ps2.bdf");

         break;         



      case 33:   // wlaczenie lub wylaczenie klawiatury

         if( klawiaturaWlaczona )

         {

               // wylaczenie klawiatury

            Sound_Holder.Stop(32);

            Sound_Holder.PlayDSound(33);



            klawiaturaWlaczona = 0;



            Sprite_Holder.ChangePhase( spriteID, 0 );

            glosnoscKlawiatury = 0;

            MuzykaStop( biezacyKlawisz );

            MuzykaStop( 24 );

            MuzykaStop( 25 );

            MuzykaStop( 26 );

            MuzykaStop( 27 );

            MuzykaStop( 28 );

         }

         else

         {

            Sound_Holder.Stop(33);

            Sound_Holder.PlayDSound(32);



            Sprite_Holder.ChangePhase( spriteID, 1 );



            //klawiaturaWlaczona = 1;

         }

         break;

   }

}





